package programs;

public class PositiveOrNegativeOrZero {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num=0;
		if(num<0)
		{
			System.out.println("negative");
		}
		else if(num>0)
		{
			System.out.println("positive");
		}
		else
		{
			System.out.println("zero");
		}

	}

}
